rows = []
for line in data.strip().split('\n'):
    parts = line.split('\t')
    if len(parts) < 12:
        continue
    
    parts = [p.strip() for p in parts]
    
    no_akta = parts[1]
    no_pendaftaran = parts[2]
    registration_date = parts[3].split(' ')[0]
    groom_name = parts[4]
    bride_name = parts[5]
    wedding_date = parts[6]
    wedding_time = parts[7] if parts[7] else "NULL"
    location = parts[8]
    officiant_name = parts[10]
    status = parts[11]
    
    def escape(s):
        if s == "NULL": return "NULL"
        return "'" + s.replace("'", "''") + "'"

    val_str = f"({escape(no_akta)}, {escape(no_pendaftaran)}, {escape(registration_date)}, {escape(groom_name)}, {escape(bride_name)}, {escape(wedding_date)}, {escape(wedding_time)}, {escape(location)}, {escape(officiant_name)}, {escape(status)})"
    rows.append(val_str)

sql = "INSERT INTO public.weddings (no_akta, no_pendaftaran, registration_date, groom_name, bride_name, wedding_date, wedding_time, location, officiant_name, status)\nVALUES\n"
sql += ",\n".join(rows) + ";"

print(sql)
